#include <iostream>

class Animal { public: virtual ~Animal() = default; };
class Dog : public Animal { int age_; public: explicit Dog(int age) : age_(age) {} int age() const { return age_; } };

int main() {
    int age{};
    if (!(std::cin >> age)) return 1;
    Dog dog(age);
    Animal& animal = dog;
    if (const auto* derived = dynamic_cast<const Dog*>(&animal)) std::cout << "dog " << derived->age() << '\n';
    else std::cout << "not-dog\n";
}
